mapper.select:
SELECT id, organization_id, name, description, color, created_at
FROM categories
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

mapper.update:
UPDATE categories
SET name = #{name},
    description = #{description},
    color = #{color}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND organization_id = #{organizationId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

mapper.delete:
DELETE FROM categories
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND organization_id = #{organizationId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
